import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

export interface PrompterSettings {
  speed: number;
  fontSize: number;
  isMirrored: boolean;
  isPlaying: boolean;
  isEditing: boolean;
}

export interface ScriptSuggestion {
  title: string;
  content: string;
}

export enum AppMode {
  EDIT = 'EDIT',
  PROMPT = 'PROMPT'
}

import { GoogleGenAI } from "@google/genai";

const apiKey = process.env.API_KEY;

// Initialize the client only if the key is available
const ai = apiKey ? new GoogleGenAI({ apiKey }) : null;

export const generateScript = async (topic: string, tone: string = 'professional'): Promise<string> => {
  if (!ai) {
    throw new Error("API Key is missing. Please configure process.env.API_KEY.");
  }

  try {
    const prompt = `Write a video script about "${topic}". The tone should be ${tone}. 
    Keep it concise (around 200-300 words). 
    Format it as plain text suitable for a teleprompter (no scene descriptions, just spoken text).`;

    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: prompt,
    });

    return response.text || "Sorry, I couldn't generate a script at this time.";
  } catch (error) {
    console.error("Gemini API Error:", error);
    throw new Error("Failed to generate script. Please try again.");
  }
};

export const polishScript = async (currentText: string): Promise<string> => {
  if (!ai) {
    throw new Error("API Key is missing.");
  }

  try {
    const prompt = `Rewrite the following teleprompter text to be more natural, better flow for speaking, and correct any grammar issues. Keep the meaning identical.

    TEXT:
    ${currentText}`;

    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: prompt,
    });

    return response.text || currentText;
  } catch (error) {
    console.error("Gemini API Error:", error);
    throw error;
  }
};

import React, { useEffect, useRef, useState } from 'react';
import { PrompterSettings } from '../types';

interface TeleprompterDisplayProps {
  settings: PrompterSettings;
  text: string;
  onTextChange: (text: string) => void;
  togglePlay: () => void;
}

const TeleprompterDisplay: React.FC<TeleprompterDisplayProps> = ({
  settings,
  text,
  onTextChange,
  togglePlay
}) => {
  const containerRef = useRef<HTMLDivElement>(null);
  const contentRef = useRef<HTMLDivElement>(null);
  const requestRef = useRef<number>();
  const lastTimeRef = useRef<number>();

  // We keep a separate ref for precise sub-pixel scrolling accumulation
  const scrollAccumulator = useRef<number>(0);

  const [isFocused, setIsFocused] = useState(false);

  // Handle auto-scrolling
  const animate = (time: number) => {
    if (settings.isPlaying && containerRef.current) {
      if (lastTimeRef.current !== undefined) {
        // Calculate delta time in seconds, but clamp it to avoid huge jumps if tab was inactive
        const deltaTime = Math.min((time - lastTimeRef.current) / 1000, 0.1);

        // Speed multiplier: map 0-10 slider to pixels per second
        // Base speed roughly 10px/s at speed 1, up to ~300px/s at speed 10
        const pixelsPerSecond = settings.speed * 20; 

        scrollAccumulator.current += pixelsPerSecond * deltaTime;

        // Apply scroll
        containerRef.current.scrollTop = scrollAccumulator.current;
      }
      lastTimeRef.current = time;
      requestRef.current = requestAnimationFrame(animate);
    }
  };

  useEffect(() => {
    if (settings.isPlaying) {
      // Sync accumulator with current scroll position when starting
      if (containerRef.current) {
        scrollAccumulator.current = containerRef.current.scrollTop;
      }
      lastTimeRef.current = undefined;
      requestRef.current = requestAnimationFrame(animate);
    } else {
      if (requestRef.current) {
        cancelAnimationFrame(requestRef.current);
      }
    }

    return () => {
      if (requestRef.current) {
        cancelAnimationFrame(requestRef.current);
      }
    };
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [settings.isPlaying, settings.speed]);

  // Handle global spacebar for play/pause
  useEffect(() => {
    const handleKeyDown = (e: KeyboardEvent) => {
      if (e.code === 'Space') {
        // If we are editing (focused in content) and not playing, allow space typing
        // If playing, space always pauses
        if (settings.isPlaying) {
          e.preventDefault();
          togglePlay();
        } else {
          // If not playing, check focus. 
          // If focused on text area, let it type space. 
          // If not focused on text area (e.g. body or buttons), toggle play.
          if (document.activeElement !== contentRef.current) {
             e.preventDefault();
             togglePlay();
          }
        }
      }
    };

    window.addEventListener('keydown', handleKeyDown);
    return () => window.removeEventListener('keydown', handleKeyDown);
  }, [settings.isPlaying, togglePlay]);

  return (
    <div className="relative flex-1 overflow-hidden bg-black w-full h-full">
      {/* Guide Line (Always centered vertically) */}
      <div className="absolute top-1/2 left-0 right-0 z-20 flex items-center justify-center pointer-events-none opacity-40">
        <div className="w-full h-0 border-t-2 border-red-500 shadow-[0_0_10px_rgba(239,68,68,0.8)]"></div>
        <div className="absolute right-4 -top-3 text-red-500 text-xs font-mono uppercase tracking-widest bg-black px-1">Eye Level</div>
      </div>

      {/* Scrollable Area */}
      <div 
        ref={containerRef}
        className={`w-full h-full overflow-y-auto no-scrollbar relative z-10 scroll-smooth ${settings.isPlaying ? 'cursor-none' : 'cursor-text'}`}
        onClick={() => {
            // Click to pause if playing
            if(settings.isPlaying) togglePlay();
        }}
      >
        {/* Padding to allow text to start and end at the center line */}
        <div style={{ height: '50vh' }}></div>

        <div 
          ref={contentRef}
          contentEditable={!settings.isPlaying}
          onInput={(e) => onTextChange(e.currentTarget.innerText)}
          onFocus={() => setIsFocused(true)}
          onBlur={() => setIsFocused(false)}
          suppressContentEditableWarning={true}
          className={`
            max-w-4xl mx-auto px-8 outline-none
            transition-all duration-300 ease-in-out
            ${settings.isMirrored ? 'scale-x-[-1]' : ''}
          `}
          style={{ 
            fontSize: `${settings.fontSize}px`,
            lineHeight: '1.5',
            color: 'white',
            textAlign: settings.isMirrored ? 'right' : 'left', // Visual fix for RTL feel when mirrored if needed, though usually scale-x is enough. Keeping left align for scale-x flip is standard for reflection.
          }}
        >
            {/* We render initial text only once to avoid cursor jumps in React contentEditable */}
            {/* In a real app we might use a proper editor lib, but for this simpler scope: */}
            {text}
        </div>

        <div style={{ height: '50vh' }}></div>
      </div>

      {/* Editing Hint Overlay */}
      {!settings.isPlaying && !isFocused && text.trim().length === 0 && (
         <div className="absolute inset-0 flex items-center justify-center pointer-events-none text-gray-500">
             <span className="text-xl">Click to start typing or paste your script...</span>
         </div>
      )}
    </div>
  );
};

export default TeleprompterDisplay;

