import React, { useEffect, useRef, useState } from 'react';
import { PrompterSettings } from '../types';

interface TeleprompterDisplayProps {
  settings: PrompterSettings;
  text: string;
  onTextChange: (text: string) => void;
  togglePlay: () => void;
}

const TeleprompterDisplay: React.FC<TeleprompterDisplayProps> = ({
  settings,
  text,
  onTextChange,
  togglePlay
}) => {
  const containerRef = useRef<HTMLDivElement>(null);
  const contentRef = useRef<HTMLDivElement>(null);
  const requestRef = useRef<number>();
  const lastTimeRef = useRef<number>();
  const scrollAccumulator = useRef<number>(0);

  // Ref to track where in the text we have last matched voice
  const lastVoiceIndexRef = useRef<number>(0);
  const recognitionRef = useRef<any>(null);

  const [isFocused, setIsFocused] = useState(false);
  const [voiceStatus, setVoiceStatus] = useState<string>('');

  // --- Animation Loop for Auto-Scroll ---
  const animate = (time: number) => {
    if (settings.isPlaying && containerRef.current) {
      if (lastTimeRef.current !== undefined) {
        const deltaTime = Math.min((time - lastTimeRef.current) / 1000, 0.1);
        const pixelsPerSecond = settings.speed * 20; 
        scrollAccumulator.current += pixelsPerSecond * deltaTime;
        containerRef.current.scrollTop = scrollAccumulator.current;
      }
      lastTimeRef.current = time;
      requestRef.current = requestAnimationFrame(animate);
    }
  };

  useEffect(() => {
    if (settings.isPlaying) {
      if (containerRef.current) {
        scrollAccumulator.current = containerRef.current.scrollTop;
      }
      lastTimeRef.current = undefined;
      requestRef.current = requestAnimationFrame(animate);
    } else {
      if (requestRef.current) cancelAnimationFrame(requestRef.current);
    }
    return () => {
      if (requestRef.current) cancelAnimationFrame(requestRef.current);
    };
  }, [settings.isPlaying, settings.speed]);

  // --- Voice Following Logic ---

  // Helper to find text node and offset at a given global character index
  const findNodeAndOffset = (root: Node, targetIndex: number): { node: Node, offset: number } | null => {
    const walker = document.createTreeWalker(root, NodeFilter.SHOW_TEXT, null);
    let currentNode = walker.nextNode();
    let currentIndex = 0;

    while (currentNode) {
      const length = currentNode.textContent?.length || 0;
      if (currentIndex + length >= targetIndex) {
        return { node: currentNode, offset: targetIndex - currentIndex };
      }
      currentIndex += length;
      currentNode = walker.nextNode();
    }
    return null;
  };

  // Scroll to a specific text index
  const scrollToTextIndex = (index: number) => {
    if (!contentRef.current || !containerRef.current) return;

    const result = findNodeAndOffset(contentRef.current, index);
    if (result) {
      try {
        const range = document.createRange();
        range.setStart(result.node, result.offset);
        range.setEnd(result.node, result.offset);
        const rect = range.getBoundingClientRect();

        // Calculate relative position within the scrollable container
        // rect.top is relative to viewport. 
        // We want to center this rect.
        // Target ScrollTop = Current ScrollTop + (Rect.top - ContainerCenter)
        const containerRect = containerRef.current.getBoundingClientRect();
        const centerOffset = containerRect.height / 2;
        const relativeTop = rect.top - containerRect.top;

        const targetScroll = containerRef.current.scrollTop + relativeTop - centerOffset;

        containerRef.current.scrollTo({
          top: targetScroll,
          behavior: 'smooth'
        });

        // Sync accumulator so if user switches back to auto-play it doesn't jump
        scrollAccumulator.current = targetScroll;

      } catch (e) {
        console.warn("Could not scroll to voice match", e);
      }
    }
  };

  useEffect(() => {
    if (settings.isVoiceMode) {
      setVoiceStatus('Listening...');
      // Reset search index when enabling voice mode
      lastVoiceIndexRef.current = 0;

      // @ts-ignore
      const SpeechRecognition = window.SpeechRecognition || window.webkitSpeechRecognition;

      if (!SpeechRecognition) {
        setVoiceStatus('Not Supported');
        alert("Your browser does not support Speech Recognition. Try Chrome.");
        return;
      }

      const recognition = new SpeechRecognition();
      recognition.continuous = true;
      recognition.interimResults = true;
      recognition.lang = 'en-US'; 

      recognition.onresult = (event: any) => {
         const results = event.results;
         // We only care about the latest result
         const latestResult = results[results.length - 1];
         const transcript = latestResult[0].transcript.trim().toLowerCase();

         // Only process if confidence is decent or it is final, or just stream it
         // To make it responsive, we use interim.

         if (contentRef.current && transcript.length > 0) {
            const fullText = contentRef.current.innerText.toLowerCase().replace(/\s+/g, ' ');
            // We search starting from a bit before the last index to allow for small corrections, 
            // but generally move forward.
            // Let's take the last few words of the transcript to match against the script
            const words = transcript.split(' ');
            const searchPhrase = words.slice(-4).join(' '); // Match last 4 words

            if (searchPhrase.length > 3) {
                // Search in the text starting from lastVoiceIndex
                // We fuzzy match by simple indexOf for now
                const matchIndex = fullText.indexOf(searchPhrase, lastVoiceIndexRef.current);

                if (matchIndex !== -1) {
                    lastVoiceIndexRef.current = matchIndex;
                    scrollToTextIndex(matchIndex);
                    setVoiceStatus(`Matched: "${searchPhrase}"`);
                } else {
                    // Fallback: If not found forward, maybe user restarted? 
                    // Optional: Search from 0 if difference is huge?
                    // For now, simple forward progression.
                }
            }
         }
      };

      recognition.onerror = (e: any) => {
          console.error("Speech error", e);
          setVoiceStatus('Error');
      };

      recognition.onend = () => {
          // Restart if still in voice mode
          if (settings.isVoiceMode && recognitionRef.current) {
              try {
                recognition.start();
              } catch(e) {}
          }
      };

      recognitionRef.current = recognition;
      try {
        recognition.start();
      } catch (e) {
          console.error(e);
      }
    } else {
      if (recognitionRef.current) {
        recognitionRef.current.stop();
        recognitionRef.current = null;
      }
      setVoiceStatus('');
    }

    return () => {
       if (recognitionRef.current) {
        recognitionRef.current.stop();
      }
    };
  }, [settings.isVoiceMode]);


  // --- Event Listeners ---
  useEffect(() => {
    const handleKeyDown = (e: KeyboardEvent) => {
      if (e.code === 'Space') {
        if (settings.isPlaying || (document.activeElement !== contentRef.current)) {
          e.preventDefault();
          togglePlay();
        }
      }
    };
    window.addEventListener('keydown', handleKeyDown);
    return () => window.removeEventListener('keydown', handleKeyDown);
  }, [settings.isPlaying, togglePlay]);

  return (
    <div className="relative flex-1 overflow-hidden bg-black w-full h-full">
      {/* Voice Status Indicator */}
      {settings.isVoiceMode && (
          <div className="absolute top-20 right-4 z-30 bg-purple-900/80 border border-purple-500 text-purple-100 px-3 py-1 rounded-full text-xs animate-pulse">
              🎤 {voiceStatus}
          </div>
      )}

      {/* Guide Line */}
      <div className="absolute top-1/2 left-0 right-0 z-20 flex items-center justify-center pointer-events-none opacity-40">
        <div className="w-full h-0 border-t-2 border-red-500 shadow-[0_0_10px_rgba(239,68,68,0.8)]"></div>
        <div className="absolute right-4 -top-3 text-red-500 text-xs font-mono uppercase tracking-widest bg-black px-1">Eye Level</div>
      </div>

      {/* Scrollable Area */}
      <div 
        ref={containerRef}
        className={`w-full h-full overflow-y-auto no-scrollbar relative z-10 scroll-smooth ${settings.isPlaying ? 'cursor-none' : 'cursor-text'}`}
        onClick={() => {
            if(settings.isPlaying) togglePlay();
        }}
      >
        <div style={{ height: '50vh' }}></div>

        <div 
          ref={contentRef}
          contentEditable={!settings.isPlaying && !settings.isVoiceMode}
          onInput={(e) => onTextChange(e.currentTarget.innerText)}
          onFocus={() => setIsFocused(true)}
          onBlur={() => setIsFocused(false)}
          suppressContentEditableWarning={true}
          className={`
            max-w-4xl mx-auto px-8 outline-none
            transition-all duration-300 ease-in-out
            ${settings.isMirrored ? 'scale-x-[-1]' : ''}
          `}
          style={{ 
            fontSize: `${settings.fontSize}px`,
            lineHeight: '1.5',
            color: 'white',
            textAlign: settings.isMirrored ? 'right' : 'left',
          }}
        >
            {text}
        </div>

        <div style={{ height: '50vh' }}></div>
      </div>

      {!settings.isPlaying && !isFocused && !settings.isVoiceMode && text.trim().length === 0 && (
         <div className="absolute inset-0 flex items-center justify-center pointer-events-none text-gray-500">
             <span className="text-xl">Click to start typing or paste your script...</span>
         </div>
      )}
    </div>
  );
};

