import React, { useEffect, useRef, useState, useMemo } from 'react';
import { PrompterSettings } from '../types';

interface TeleprompterDisplayProps {
  settings: PrompterSettings;
  text: string;
  onTextChange: (text: string) => void;
  togglePlay: () => void;
}

const TeleprompterDisplay: React.FC<TeleprompterDisplayProps> = ({
  settings,
  text,
  onTextChange,
  togglePlay
}) => {
  const containerRef = useRef<HTMLDivElement>(null);
  const contentRef = useRef<HTMLDivElement>(null);
  const requestRef = useRef<number>();
  const lastTimeRef = useRef<number>();
  const scrollAccumulator = useRef<number>(0);

  // Voice State
  const recognitionRef = useRef<any>(null);
  const [voiceStatus, setVoiceStatus] = useState<string>('');

  // Track the normalized index of the last match to ensure forward progression
  const lastMatchIndexRef = useRef<number>(0);

  const [isFocused, setIsFocused] = useState(false);

  // --- Preprocessing for Robust Matching ---
  // We create a "normalized" version of the text (lowercase, no punctuation/spaces)
  // and a map that links each character in the normalized string back to the original text index.
  const { normalizedText, indexMap } = useMemo(() => {
    let normalized = "";
    const map: number[] = [];

    // Iterate manually to build the map
    // Using regex for letters/numbers in any language (Unicode property escapes)
    // \p{L} = Any Unicode Letter, \p{N} = Any Unicode Number
    const regex = /[\p{L}\p{N}]/u;

    for (let i = 0; i < text.length; i++) {
      const char = text[i];
      if (regex.test(char)) {
        normalized += char.toLowerCase();
        map.push(i);
      }
    }

    return { normalizedText: normalized, indexMap: map };
  }, [text]);

  // Reset match index when text changes significantly or mode changes
  useEffect(() => {
    lastMatchIndexRef.current = 0;
  }, [normalizedText, settings.isVoiceMode]);

  // --- Animation Loop for Auto-Scroll ---
  const animate = (time: number) => {
    if (settings.isPlaying && containerRef.current) {
      if (lastTimeRef.current !== undefined) {
        const deltaTime = Math.min((time - lastTimeRef.current) / 1000, 0.1);
        const pixelsPerSecond = settings.speed * 20; 
        scrollAccumulator.current += pixelsPerSecond * deltaTime;
        containerRef.current.scrollTop = scrollAccumulator.current;
      }
      lastTimeRef.current = time;
      requestRef.current = requestAnimationFrame(animate);
    }
  };

  useEffect(() => {
    if (settings.isPlaying) {
      if (containerRef.current) {
        scrollAccumulator.current = containerRef.current.scrollTop;
      }
      lastTimeRef.current = undefined;
      requestRef.current = requestAnimationFrame(animate);
    } else {
      if (requestRef.current) cancelAnimationFrame(requestRef.current);
    }
    return () => {
      if (requestRef.current) cancelAnimationFrame(requestRef.current);
    };
  }, [settings.isPlaying, settings.speed]);

  // --- Voice Following Logic ---

  const scrollToOriginalIndex = (originalIndex: number) => {
    if (!contentRef.current || !containerRef.current) return;

    // Find the text node containing this index
    const walker = document.createTreeWalker(contentRef.current, NodeFilter.SHOW_TEXT, null);
    let currentNode = walker.nextNode();
    let currentIndex = 0;

    while (currentNode) {
      const len = currentNode.textContent?.length || 0;
      if (currentIndex + len > originalIndex) {
        const offset = originalIndex - currentIndex;

        try {
          const range = document.createRange();
          range.setStart(currentNode, offset);
          range.setEnd(currentNode, offset);
          const rect = range.getBoundingClientRect();

          const containerRect = containerRef.current.getBoundingClientRect();
          const centerOffset = containerRect.height / 2;
          const relativeTop = rect.top - containerRect.top;

          // Target scroll position
          const targetScroll = containerRef.current.scrollTop + relativeTop - centerOffset;

          // Smooth scroll to it
          containerRef.current.scrollTo({
            top: targetScroll,
            behavior: 'smooth'
          });

          // Sync accumulator
          scrollAccumulator.current = targetScroll;
        } catch (e) {
          // Range errors can happen if dom shifted
        }
        break;
      }
      currentIndex += len;
      currentNode = walker.nextNode();
    }
  };

  useEffect(() => {
    if (settings.isVoiceMode) {
      setVoiceStatus('Initializing...');

      // @ts-ignore
      const SpeechRecognition = window.SpeechRecognition || window.webkitSpeechRecognition;

      if (!SpeechRecognition) {
        setVoiceStatus('Not Supported');
        alert("Speech Recognition API not found. Please use Chrome or Safari.");
        return;
      }

      const recognition = new SpeechRecognition();
      recognition.continuous = true;
      recognition.interimResults = true;
      // Use browser language or default to English. 
      recognition.lang = navigator.language || 'en-US'; 

      recognition.onstart = () => {
        setVoiceStatus('Listening...');
      };

      recognition.onresult = (event: any) => {
         // Get the latest result
         const results = event.results;
         const latestResult = results[results.length - 1];
         const transcript = latestResult[0].transcript;

         // Normalize the transcript exactly like we normalized the script
         let cleanTranscript = "";
         const regex = /[\p{L}\p{N}]/u;
         for (const char of transcript) {
            if (regex.test(char)) cleanTranscript += char.toLowerCase();
         }

         if (cleanTranscript.length === 0) return;

         // Logic: match the TAIL of the transcript to the script.
         // We take a window of the last N characters from transcript to match.
         const searchWindowSize = 25; 
         const searchStr = cleanTranscript.slice(-searchWindowSize);

         // Search in normalizedText starting from lastMatchIndex
         // We allow a small lookback (e.g. 10 chars) in case we drifted, but mostly look forward.
         const lookback = 10;
         const startSearch = Math.max(0, lastMatchIndexRef.current - lookback);

         const matchIndex = normalizedText.indexOf(searchStr, startSearch);

         if (matchIndex !== -1) {
             // We found a match!
             // The "current position" is the end of that match.
             const newCurrentIndex = matchIndex + searchStr.length;

             // Update ref
             lastMatchIndexRef.current = newCurrentIndex;

             // Map back to original text index
             // indexMap[k] gives the original index for the k-th normalized char.
             // We want the character corresponding to the end of the match.
             const originalIndex = indexMap[Math.min(newCurrentIndex, indexMap.length - 1)];

             if (originalIndex !== undefined) {
                 scrollToOriginalIndex(originalIndex);
                 setVoiceStatus(`Matched: "...${searchStr.slice(-10)}..."`);
             }
         }
      };

      recognition.onerror = (e: any) => {
          console.error("Speech error", e);
          if (e.error === 'not-allowed') {
              setVoiceStatus('Microphone Blocked');
          } else {
              setVoiceStatus('Retrying...');
          }
      };

      recognition.onend = () => {
          // Auto-restart if still enabled
          if (settings.isVoiceMode && recognitionRef.current) {
              try {
                  recognition.start();
              } catch(e) {
                  // ignore
              }
          } else {
              setVoiceStatus('');
          }
      };

      recognitionRef.current = recognition;
      try {
        recognition.start();
      } catch (e) {
          console.error(e);
      }
    } else {
      if (recognitionRef.current) {
        recognitionRef.current.onend = null; // Prevent auto-restart
        recognitionRef.current.stop();
        recognitionRef.current = null;
      }
      setVoiceStatus('');
    }

    return () => {
       if (recognitionRef.current) {
        recognitionRef.current.onend = null;
        recognitionRef.current.stop();
      }
    };
  }, [settings.isVoiceMode, normalizedText, indexMap]);

  // --- Event Listeners ---
  useEffect(() => {
    const handleKeyDown = (e: KeyboardEvent) => {
      if (e.code === 'Space') {
        if (settings.isPlaying || (document.activeElement !== contentRef.current)) {
          e.preventDefault();
          togglePlay();
        }
      }
    };
    window.addEventListener('keydown', handleKeyDown);
    return () => window.removeEventListener('keydown', handleKeyDown);
  }, [settings.isPlaying, togglePlay]);

  return (
    <div className="relative flex-1 overflow-hidden bg-black w-full h-full">
      {/* Voice Status Indicator */}
      {settings.isVoiceMode && (
          <div className="absolute top-20 right-4 z-30 flex items-center gap-2">
               <div className="bg-purple-900/90 border border-purple-500 text-purple-100 px-4 py-2 rounded-full text-xs font-mono shadow-[0_0_15px_rgba(168,85,247,0.5)] flex items-center gap-2 animate-pulse">
