  const readOnlyContentRef = useRef<HTMLDivElement>(null);

  const requestRef = useRef<number>();
  const lastTimeRef = useRef<number>();
  const scrollAccumulator = useRef<number>(0);

  // Voice State
  const recognitionRef = useRef<any>(null);
  const [voiceStatus, setVoiceStatus] = useState<string>('');

  // Track the normalized index of the last match
  const lastMatchIndexRef = useRef<number>(0);
  // State to trigger re-renders for highlighting
  const [matchedIndex, setMatchedIndex] = useState<number>(0);

  const [isFocused, setIsFocused] = useState(false);
  const [fatalError, setFatalError] = useState(false);

  // --- Preprocessing: Split text into segments for highlighting ---
  const { segments, normalizedText } = useMemo(() => {
    const segs: TextSegment[] = [];
    let normStr = "";
    let currentNormIndex = 0;

    // Regex to match "word" characters (letters, numbers)
    // We add common CJK ranges explicitly to ensure they are treated as words if \p{L} is not sufficient in some browsers
    const wordRegex = /[\p{L}\p{N}]/u;

    let buffer = "";
    let bufferIsWord = false;

    // Helper to flush buffer to segments
    const flush = () => {
      if (buffer.length === 0) return;

      let normLen = 0;
      if (bufferIsWord) {
        for (const char of buffer) {
           if (wordRegex.test(char)) {
             normStr += char.toLowerCase();
             normLen++;
           }
        }
      }

      segs.push({
        text: buffer,
        isWord: bufferIsWord,
        start: currentNormIndex,
        end: currentNormIndex + normLen
      });

      currentNormIndex += normLen;
      buffer = "";
    };

    for (const char of text) {
      const charIsWord = wordRegex.test(char);

      if (buffer.length === 0) {
        bufferIsWord = charIsWord;
      } else if (charIsWord !== bufferIsWord) {
        flush();
        bufferIsWord = charIsWord;
      }
      buffer += char;
    }
    flush();

    return { segments: segs, normalizedText: normStr };
  }, [text]);

  // Reset match index when text changes significantly or mode changes
  useEffect(() => {
    lastMatchIndexRef.current = 0;
    setMatchedIndex(0);
    setFatalError(false);
  }, [normalizedText, settings.isVoiceMode]);

  // --- Animation Loop for Auto-Scroll ---
  const animate = (time: number) => {
    if (settings.isPlaying && containerRef.current) {
      if (lastTimeRef.current !== undefined) {
        const deltaTime = Math.min((time - lastTimeRef.current) / 1000, 0.1);
        const pixelsPerSecond = settings.speed * 20; 
        scrollAccumulator.current += pixelsPerSecond * deltaTime;
        containerRef.current.scrollTop = scrollAccumulator.current;
      }
      lastTimeRef.current = time;
      requestRef.current = requestAnimationFrame(animate);
    }
  };

  useEffect(() => {
    if (settings.isPlaying) {
      if (containerRef.current) {
        scrollAccumulator.current = containerRef.current.scrollTop;
      }
      lastTimeRef.current = undefined;
      requestRef.current = requestAnimationFrame(animate);
    } else {
      if (requestRef.current) cancelAnimationFrame(requestRef.current);
    }
    return () => {
      if (requestRef.current) cancelAnimationFrame(requestRef.current);
    };
  }, [settings.isPlaying, settings.speed]);

  // --- Voice Following Logic ---

  const scrollToActiveSegment = () => {
    if (!readOnlyContentRef.current || !containerRef.current) return;

    // Find the currently active highlighted span. 
    const activeSpan = readOnlyContentRef.current.querySelector('[data-active="true"]');

    if (activeSpan) {
        try {
          const rect = activeSpan.getBoundingClientRect();
          const containerRect = containerRef.current.getBoundingClientRect();
          const centerOffset = containerRect.height / 2;
          // Target scroll: Element Top + Half Element Height - Container Half Height
          // This centers the element
          const relativeTop = rect.top - containerRect.top;
          const targetScroll = containerRef.current.scrollTop + relativeTop - centerOffset + (rect.height / 2);

          containerRef.current.scrollTo({
            top: targetScroll,
            behavior: 'smooth'
          });

          // Sync accumulator
          scrollAccumulator.current = targetScroll;
        } catch (e) {
          // ignore layout shifts
        }
    }
  };

  useEffect(() => {
    if (settings.isVoiceMode && !fatalError) {
      setVoiceStatus('Initializing...');

      // @ts-ignore
      const SpeechRecognition = window.SpeechRecognition || window.webkitSpeechRecognition;

      if (!SpeechRecognition) {
        setVoiceStatus('Not Supported');
        alert("Speech Recognition API not found. Please use Chrome or Safari.");
        return;
      }

      const recognition = new SpeechRecognition();
      recognition.continuous = true;
      recognition.interimResults = true;
      recognition.lang = navigator.language || 'en-US'; 

      recognition.onstart = () => {
        setVoiceStatus('Listening...');
      };

      recognition.onresult = (event: any) => {
         const results = event.results;
         const latestResult = results[results.length - 1];
         const transcript = latestResult[0].transcript;

         // Normalize transcript
         let cleanTranscript = "";
         const regex = /[\p{L}\p{N}]/u;
         for (const char of transcript) {
            if (regex.test(char)) cleanTranscript += char.toLowerCase();
         }

         if (cleanTranscript.length === 0) return;

         // Robust matching strategy:
         // Look for the last N characters of the transcript in the script
         // starting near where we last left off.
         const searchWindowSize = 40; 
         const searchStr = cleanTranscript.slice(-searchWindowSize);

         const lookback = 20;
         const startSearch = Math.max(0, lastMatchIndexRef.current - lookback);

         // Search forward first
         let matchIndex = normalizedText.indexOf(searchStr, startSearch);

         // If not found, and transcript is short (start of sentence?), maybe search closely?
         // For now, simple forward search is usually best for teleprompters.

         if (matchIndex !== -1) {
             const newCurrentIndex = matchIndex + searchStr.length;

             // Validation: Don't jump backwards too far (allow small corrections)
             // and don't jump massively forward unless confident (not handled here but implicit in prompt usage)
             if (newCurrentIndex > lastMatchIndexRef.current - 5) {
                 lastMatchIndexRef.current = newCurrentIndex;
                 setMatchedIndex(newCurrentIndex);
                 setVoiceStatus(`Matched: "...${searchStr.slice(-15)}..."`);
             }
         }
      };

      recognition.onerror = (event: any) => {
          // Safely extract error message
          const errorMsg = event.error ? String(event.error) : 'Unknown Error';

          if (errorMsg === 'no-speech') {
             // Benign error, just silence
             return;
          } 

          console.warn("Speech Recognition Error:", errorMsg);

          if (errorMsg === 'not-allowed' || errorMsg === 'service-not-allowed') {
              setVoiceStatus('Microphone Blocked');
              setFatalError(true); // Prevent restart loop
              if (recognitionRef.current) recognitionRef.current.stop();
          } else if (errorMsg === 'network') {
               setVoiceStatus('Network Error');
          } else {
              setVoiceStatus(`Error: ${errorMsg}`);
          }
      };

      recognition.onend = () => {
          // Only restart if we are still in voice mode and didn't hit a fatal error
          // We use a timeout to prevent rapid-fire restart loops in some edge cases
          if (settings.isVoiceMode && !fatalError) {
             setTimeout(() => {
                 if (recognitionRef.current && !fatalError) {
                    try {
                        recognition.start();
                    } catch(e) { /* ignore */ }
                 }
             }, 100);
          } else {
              setVoiceStatus('');
          }
      };

      recognitionRef.current = recognition;
      try {
        recognition.start();
      } catch (e) {
          console.error("Failed to start recognition", e);
      }
    } else {
      if (recognitionRef.current) {
        // Clear onend to prevent restart during cleanup
        recognitionRef.current.onend = null;
        recognitionRef.current.stop();
        recognitionRef.current = null;
      }
      setVoiceStatus('');
      if (!settings.isVoiceMode) setMatchedIndex(0);
    }

    return () => {
       if (recognitionRef.current) {
        recognitionRef.current.onend = null;
        recognitionRef.current.stop();
      }
    };
  }, [settings.isVoiceMode, fatalError, normalizedText]);

  // Effect to scroll whenever matchedIndex changes (Voice Mode only)
  useEffect(() => {
     if (settings.isVoiceMode) {
         scrollToActiveSegment();
     }
  }, [matchedIndex, settings.isVoiceMode]);


  // --- Event Listeners ---
  useEffect(() => {
    const handleKeyDown = (e: KeyboardEvent) => {
      if (e.code === 'Space') {
        // Prevent default only if we are not editing
        if (settings.isPlaying || settings.isVoiceMode || document.activeElement !== contentEditableRef.current) {
          e.preventDefault();
          togglePlay();
        }
      }
    };
    window.addEventListener('keydown', handleKeyDown);
    return () => window.removeEventListener('keydown', handleKeyDown);
  }, [settings.isPlaying, settings.isVoiceMode, togglePlay]);

  // Determine if we are in "Read Only" mode (Playing or Voice)
  const isReadOnlyMode = settings.isPlaying || settings.isVoiceMode;

  return (
    <div className="relative flex-1 overflow-hidden bg-black w-full h-full">
      {/* Voice Status Indicator */}
      {settings.isVoiceMode && (
          <div className="absolute top-20 right-4 z-30 flex items-center gap-2 pointer-events-none">
               <div className={`
                 px-4 py-2 rounded-full text-xs font-mono shadow-lg flex items-center gap-2 transition-all
                 ${fatalError ? 'bg-red-900/90 border border-red-500 text-red-100' : 'bg-purple-900/90 border border-purple-500 text-purple-100 animate-pulse'}
               `}>
                  {!fatalError && <div className="w-2 h-2 bg-red-500 rounded-full animate-ping"></div>}
                  {voiceStatus}
               </div>
          </div>
      )}

      {/* Guide Line (Only show if not empty) */}
      <div className="absolute top-1/2 left-0 right-0 z-20 flex items-center justify-center pointer-events-none opacity-40">
        <div className="w-full h-0 border-t-2 border-red-500 shadow-[0_0_10px_rgba(239,68,68,0.8)]"></div>
        <div className="absolute right-4 -top-3 text-red-500 text-xs font-mono uppercase tracking-widest bg-black px-1">Eye Level</div>
      </div>

      {/* Scrollable Area */}
      <div 
        ref={containerRef}
        className={`w-full h-full overflow-y-auto no-scrollbar relative z-10 scroll-smooth ${isReadOnlyMode ? 'cursor-none' : 'cursor-text'}`}
        onClick={() => {
            if(settings.isPlaying) togglePlay();
        }}
      >
        <div style={{ height: '50vh' }}></div>

        {/* Edit View */}
        <div 
          ref={contentEditableRef}
          contentEditable={!isReadOnlyMode}
          onInput={(e) => onTextChange(e.currentTarget.innerText)}
          onFocus={() => setIsFocused(true)}
          onBlur={() => setIsFocused(false)}
          suppressContentEditableWarning={true}
          className={`
            max-w-4xl mx-auto px-8 outline-none
            transition-all duration-300 ease-in-out
            ${settings.isMirrored ? 'scale-x-[-1]' : ''}
            ${isReadOnlyMode ? 'hidden' : 'block'}
          `}
          style={{ 
            fontSize: `${settings.fontSize}px`,
            lineHeight: '1.5',
            color: 'white',
            textAlign: settings.isMirrored ? 'right' : 'left',
            whiteSpace: 'pre-wrap' 
          }}
        >
            {text}
        </div>

        {/* Read/Voice View */}
        {isReadOnlyMode && (
             <div 
                ref={readOnlyContentRef}
                className={`
                    max-w-4xl mx-auto px-8 outline-none
                    transition-all duration-300 ease-in-out
                    ${settings.isMirrored ? 'scale-x-[-1]' : ''}
                `}
                style={{ 
                    fontSize: `${settings.fontSize}px`,
                    lineHeight: '1.5',
                    textAlign: settings.isMirrored ? 'right' : 'left',
                    whiteSpace: 'pre-wrap',
                    color: 'white'
                }}
             >
                {segments.map((seg, i) => {
                    // Logic:
                    // 1. Spoken words (end <= matchedIndex): Dimmed/Gray
                    // 2. Active word (contains matchedIndex): Highlight Background
                    // 3. Future words: White

                    const isFullyRead = seg.isWord && seg.end <= matchedIndex;
                    // Active if the match index is within this word (or extremely close to the start)
                    const isActive = seg.isWord && !isFullyRead && (seg.start < matchedIndex || (i > 0 && segments[i-1].end <= matchedIndex));

                    // Actually, simpler logic for "Current":
                    // The "Current" word is the first word that hasn't been fully read yet.
                    // So we find the first segment where seg.end > matchedIndex.

                    let status = 'future';
                    if (seg.isWord) {
                        if (seg.end <= matchedIndex) {
                            status = 'read';
                        } else if (seg.start <= matchedIndex) {
                            // Overlap
                            status = 'active';
                        } else {
                            // Future, but check if it is the VERY NEXT word after match
                            // We can approximate this by checking if the previous word was read.
                            // But since we map linearly, we can just say: if not read and not active, it's future.
                            // However, we want to highlight the word user is *about* to say or *saying*.
                            // The match index points to the end of what was *just recognized*. 
                            // So the *next* word is the one to highlight.
                        }
                    }

                    // Let's refine based on user request "add background behind the word".
                    // Usually this means the word currently being spoken. 
                    // Since speech recognition has latency, `matchedIndex` is usually the end of the *last spoken word*.
                    // So we should highlight the *next* word (the one at matchedIndex).

                    const isNextWord = seg.isWord && seg.start >= matchedIndex && (
                        // It is the first word satisfying this
                        i === 0 || segments[i-1].end <= matchedIndex
                    );

                    // Re-eval logic for simple robust visuals
                    // Gray out everything before matchedIndex
                    // Highlight the word AT matchedIndex

                    const isPast = seg.isWord && seg.end <= matchedIndex;
                    const isCurrent = seg.isWord && !isPast && (seg.start <= matchedIndex + 1); // Tolerance

                    // Actually, let's look at the implementation of `isLastHighlighted` previously.
                    // We want to highlight the word that corresponds to `matchedIndex`.

                    // Let's rely on:
                    // Read: Gray
                    // Current: Blue Background
                    // Future: White

                    let className = "transition-colors duration-200 rounded px-1 -mx-1 ";

                    if (!seg.isWord) {
                        // Punctuation: dim if surrounding words are read
                        const prevRead = i > 0 && segments[i-1].end <= matchedIndex;
                        const nextRead = i < segments.length - 1 && segments[i+1].end <= matchedIndex;
                        if (prevRead) className += "text-gray-600";
                        else className += "text-white";
                    } else {
                        if (isPast) {
                            className += "text-gray-600"; // Read
                        } else if (isNextWord) {
                            className += "bg-blue-600 text-white shadow-[0_0_15px_rgba(37,99,235,0.5)] scale-105 inline-block origin-center transform"; // Current
                        } else {
                            className += "text-white"; // Future
                        }
                    }

                    return (
                        <span 
                            key={i} 
                            data-active={isNextWord ? "true" : "false"}
                            className={className}
                        >
                            {seg.text}
                        </span>
                    );
                })}
             </div>
        )}

        <div style={{ height: '50vh' }}></div>
      </div>

      {!isReadOnlyMode && !isFocused && text.trim().length === 0 && (
         <div className="absolute inset-0 flex items-center justify-center pointer-events-none text-gray-500">
             <span className="text-xl">Click to start typing or paste your script...</span>
         </div>
      )}
    </div>
  );
};

