import React from 'react';
import { PrompterSettings } from '../types';

interface ControlPanelProps {
  settings: PrompterSettings;
  updateSettings: (newSettings: Partial<PrompterSettings>) => void;
  togglePlay: () => void;
  onReset: () => void;
  openAIModal: () => void;
  openHelpModal: () => void;
}

const ControlPanel: React.FC<ControlPanelProps> = ({
  settings,
  updateSettings,
  togglePlay,
  onReset,
  openAIModal,
  openHelpModal
}) => {
  // Helper to adjust speed safely
  const adjustSpeed = (delta: number) => {
    const newSpeed = Math.max(0, Math.min(10, settings.speed + delta));
    // Round to 1 decimal to avoid floating point weirdness
    const roundedSpeed = Math.round(newSpeed * 10) / 10;
    updateSettings({ speed: roundedSpeed });
  };

  return (
    <div className="bg-gray-900 border-t border-gray-800 p-4 w-full z-50">
      <div className="max-w-6xl mx-auto flex flex-col md:flex-row items-center justify-between gap-4">

        {/* Primary Actions */}
        <div className="flex items-center gap-3 w-full md:w-auto">
          <button
            onClick={togglePlay}
            disabled={settings.isVoiceMode}
            className={`
              flex-1 md:flex-none px-6 py-3 rounded-lg font-bold text-white transition-all transform hover:scale-105 active:scale-95
              ${settings.isVoiceMode ? 'bg-gray-800 text-gray-500 cursor-not-allowed' : (settings.isPlaying ? 'bg-red-600 hover:bg-red-700 shadow-red-900/20' : 'bg-emerald-600 hover:bg-emerald-700 shadow-emerald-900/20')}
              shadow-lg
            `}
          >
            {settings.isPlaying ? (
               <span className="flex items-center justify-center gap-2">
                 <svg xmlns="http://www.w3.org/2000/svg" width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"><rect x="6" y="4" width="4" height="16"></rect><rect x="14" y="4" width="4" height="16"></rect></svg>
                 PAUSE
               </span>
            ) : (
                <span className="flex items-center justify-center gap-2">
                 <svg xmlns="http://www.w3.org/2000/svg" width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"><polygon points="5 3 19 12 5 21 5 3"></polygon></svg>
                 START
               </span>
            )}
          </button>

          <button
            onClick={onReset}
            title="Reset Scroll"
            className="p-3 rounded-lg bg-gray-800 text-gray-400 hover:text-white hover:bg-gray-700 transition-colors"
          >
            <svg xmlns="http://www.w3.org/2000/svg" width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"><path d="M3 12a9 9 0 1 0 9-9 9.75 9.75 0 0 0-6.74 2.74L3 12"></path><polyline points="3 8 3 12 7 12"></polyline></svg>
          </button>

          <button
            onClick={() => updateSettings({ isVoiceMode: !settings.isVoiceMode, isPlaying: false })}
            className={`p-3 rounded-lg transition-all border ${settings.isVoiceMode ? 'bg-purple-600 border-purple-500 text-white shadow-[0_0_15px_rgba(147,51,234,0.5)]' : 'bg-gray-800 border-gray-700 text-gray-400 hover:text-white'}`}
            title={settings.isVoiceMode ? "Disable Voice Mode" : "Enable Voice Following Mode"}
          >
             <svg xmlns="http://www.w3.org/2000/svg" width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"><path d="M12 2a3 3 0 0 0-3 3v7a3 3 0 0 0 6 0V5a3 3 0 0 0-3-3Z"/><path d="M19 10v2a7 7 0 0 1-14 0v-2"/><line x1="12" y1="19" x2="12" y2="22"/></svg>
          </button>
        </div>

        {/* Speed Controls (Enhanced) */}
        <div className="flex-1 w-full md:w-auto flex flex-col gap-2 px-2">
            <div className="flex justify-between text-xs text-gray-400 uppercase tracking-wider font-semibold">
                <span>Speed</span>
                <span className="text-emerald-400">{settings.speed.toFixed(1)}</span>
            </div>

            <div className="flex items-center gap-2">
                <button 
                    onClick={() => adjustSpeed(-0.5)}
                    className="w-8 h-8 rounded bg-gray-800 text-white hover:bg-gray-700 flex items-center justify-center font-bold active:bg-gray-600 select-none"
                    title="Decrease Speed (-0.5)"
                >
                    -
                </button>
                <input
                    type="range"
                    min="0"
                    max="10"
                    step="0.1"
                    value={settings.speed}
                    onChange={(e) => updateSettings({ speed: parseFloat(e.target.value) })}
                    className="flex-1 h-2 bg-gray-700 rounded-lg appearance-none cursor-pointer accent-emerald-500"
                />
                <button 
                     onClick={() => adjustSpeed(0.5)}
                     className="w-8 h-8 rounded bg-gray-800 text-white hover:bg-gray-700 flex items-center justify-center font-bold active:bg-gray-600 select-none"
                     title="Increase Speed (+0.5)"
                >
                    +
                </button>
            </div>

            {/* Speed Presets */}
            <div className="flex justify-between gap-1">
                {[1, 1.5, 2, 3, 5].map(s => (
                     <button 
                        key={s}
                        onClick={() => updateSettings({ speed: s })}
                        className={`text-[10px] px-3 py-1 rounded bg-gray-800 hover:bg-gray-700 text-gray-400 transition-colors ${settings.speed === s ? 'text-emerald-400 font-bold border border-emerald-500/30' : ''}`}
                     >
                        {s}x
                     </button>
                ))}
            </div>
        </div>

        {/* Font Size & Extras */}
        <div className="flex items-center gap-4 w-full md:w-auto justify-end">
            <div className="flex flex-col gap-1 w-24">
                 <div className="flex justify-between text-xs text-gray-400 uppercase tracking-wider font-semibold">
                    <span>Size</span>
                    <span>{settings.fontSize}px</span>
                </div>
                <input
                    type="range"
                    min="20"
                    max="150"
                    step="2"
                    value={settings.fontSize}
                    onChange={(e) => updateSettings({ fontSize: parseInt(e.target.value) })}
                    className="w-full h-2 bg-gray-700 rounded-lg appearance-none cursor-pointer accent-emerald-500"
                />
            </div>

             <button
                onClick={() => updateSettings({ isMirrored: !settings.isMirrored })}
                className={`p-3 rounded-lg transition-colors border ${settings.isMirrored ? 'bg-blue-600 border-blue-500 text-white' : 'bg-gray-800 border-gray-700 text-gray-400 hover:text-white'}`}
                title="Mirror Flip"
            >
               <svg xmlns="http://www.w3.org/2000/svg" width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"><path d="m3 9 9-7 9 7v11a2 2 0 0 1-2 2H5a2 2 0 0 1-2-2z"/><polyline points="9 22 9 12 15 12 15 22"/></svg>
            </button>

            <button
                onClick={openHelpModal}
                className="p-3 rounded-lg bg-gray-800 border border-gray-700 text-gray-400 hover:text-white hover:bg-gray-700 transition-colors"
                title="Help & Usage"
            >
                <svg xmlns="http://www.w3.org/2000/svg" width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"><circle cx="12" cy="12" r="10"></circle><path d="M9.09 9a3 3 0 0 1 5.83 1c0 2-3 3-3 3"></path><line x1="12" y1="17" x2="12.01" y2="17"></line></svg>
            </button>

             <button
                onClick={openAIModal}
                className="flex items-center gap-2 px-4 py-3 rounded-lg bg-gradient-to-r from-purple-600 to-indigo-600 text-white font-semibold hover:from-purple-500 hover:to-indigo-500 transition-all shadow-lg shadow-indigo-900/30"
            >
                <svg xmlns="http://www.w3.org/2000/svg" width="18" height="18" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"><path d="M12 2a10 10 0 1 0 10 10H12V2z"></path><path d="M12 2a10 10 0 0 1 10 10h-10V2z" opacity="0.5"></path><path d="m21.41 10.23-1.64-1.65"></path><path d="m10.24 21.41-1.65-1.64"></path><path d="m2 12h10"></path></svg>
                AI
            </button>
        </div>
      </div>
    </div>
  );
};

