import React, { useState, useEffect } from 'react';
import TeleprompterDisplay from './components/TeleprompterDisplay';
import ControlPanel from './components/ControlPanel';
import AIModal from './components/AIModal';
import HelpModal from './components/HelpModal';
import { PrompterSettings } from './types';

const App: React.FC = () => {
  // --- State ---
  const [text, setText] = useState<string>(`Welcome to ZenPrompter.

Click here to edit this text, or paste your own script.

Press "Space" or the Start button below to begin scrolling.

Use the controls to adjust speed, mirror text, or enable Voice Mode to scroll as you speak.

Try the "AI Script" button to generate content instantly!`);

  const [settings, setSettings] = useState<PrompterSettings>({
    speed: 2,
    fontSize: 60,
    isMirrored: false,
    isPlaying: false,
    isEditing: true,
    isVoiceMode: false
  });

  const [isAIModalOpen, setAIModalOpen] = useState(false);
  const [isHelpModalOpen, setHelpModalOpen] = useState(false);

  // --- Handlers ---
  const handleTextChange = (newText: string) => {
    setText(newText);
  };

  const updateSettings = (newSettings: Partial<PrompterSettings>) => {
    setSettings(prev => ({ ...prev, ...newSettings }));
  };

  const togglePlay = () => {
    // If voice mode is on, playing manually turns it off or handles it differently
    if (settings.isVoiceMode) {
      setSettings(prev => ({ ...prev, isPlaying: !prev.isPlaying, isVoiceMode: false }));
    } else {
      setSettings(prev => ({ ...prev, isPlaying: !prev.isPlaying }));
    }
  };

  const handleReset = () => {
    setSettings(prev => ({ ...prev, isPlaying: false, isVoiceMode: false }));
    const scroller = document.querySelector('.overflow-y-auto');
    if (scroller) scroller.scrollTop = 0;
  };

  const handleAIApply = (generatedText: string) => {
    setText(generatedText);
    handleReset();
  };

  return (
    <div className="flex flex-col h-screen bg-black overflow-hidden font-sans">
      {/* Header / Top Bar (Minimalist) */}
      <div className="absolute top-0 left-0 p-4 z-40 opacity-50 hover:opacity-100 transition-opacity">
        <h1 className="text-white font-bold tracking-tighter text-xl pointer-events-none select-none">
          Zen<span className="text-red-500">Prompter</span>
        </h1>
      </div>

      {/* Main Display */}
      <TeleprompterDisplay 
        settings={settings} 
        text={text} 
        onTextChange={handleTextChange} 
        togglePlay={togglePlay}
      />

      {/* Controls */}
      <ControlPanel 
        settings={settings} 
        updateSettings={updateSettings} 
        togglePlay={togglePlay}
        onReset={handleReset}
        openAIModal={() => setAIModalOpen(true)}
        openHelpModal={() => setHelpModalOpen(true)}
      />

      {/* AI Modal */}
      <AIModal 
        isOpen={isAIModalOpen} 
        onClose={() => setAIModalOpen(false)}
        onApply={handleAIApply}
        currentText={text}
      />

      {/* Help Modal */}
      <HelpModal 
        isOpen={isHelpModalOpen}
        onClose={() => setHelpModalOpen(false)}
      />
    </div>
  );
};

export default App;

