import React, { useState, useEffect } from 'react';
import TeleprompterDisplay from './components/TeleprompterDisplay';
import ControlPanel from './components/ControlPanel';
import AIModal from './components/AIModal';
import HelpModal from './components/HelpModal';
import { PrompterSettings } from './types';

const App: React.FC = () => {
  // --- State ---
  const [text, setText] = useState<string>(`Welcome to ZenPrompter.

Click here to edit this text, or paste your own script.

Press "Space" or the Start button below to begin scrolling.

Use the controls to adjust speed, mirror text, or enable Voice Mode to scroll as you speak.

Try the "AI Script" button to generate content instantly!`);

  const [settings, setSettings] = useState<PrompterSettings>({
    speed: 2,
    fontSize: 60,
    isMirrored: false,
    isPlaying: false,
    isEditing: true,
    isVoiceMode: false,
    fontFamily: 'sans',
    textColor: 'white'
  });

  const [isAIModalOpen, setAIModalOpen] = useState(false);
  const [isHelpModalOpen, setHelpModalOpen] = useState(false);
  const [isDragging, setIsDragging] = useState(false);

  // --- Persistence ---
  useEffect(() => {
    const savedText = localStorage.getItem('zen_text');
    const savedSettings = localStorage.getItem('zen_settings');

    if (savedText) setText(savedText);
    if (savedSettings) {
        try {
            const parsed = JSON.parse(savedSettings);
            // Merge with defaults to handle new fields in updates
            setSettings(prev => ({
                ...prev,
                ...parsed,
                isPlaying: false, 
                isVoiceMode: false 
            }));
        } catch(e) { console.error("Failed to load settings"); }
    }
  }, []);

  useEffect(() => {
    localStorage.setItem('zen_text', text);
    // Don't save playing/voice states
    const { isPlaying, isVoiceMode, ...toSave } = settings;
    localStorage.setItem('zen_settings', JSON.stringify(toSave));
  }, [text, settings]);


  // --- Handlers ---
  const handleTextChange = (newText: string) => {
    setText(newText);
  };

  const updateSettings = (newSettings: Partial<PrompterSettings>) => {
    setSettings(prev => ({ ...prev, ...newSettings }));
  };

  const togglePlay = () => {
    if (settings.isVoiceMode) {
      setSettings(prev => ({ ...prev, isPlaying: !prev.isPlaying, isVoiceMode: false }));
    } else {
      setSettings(prev => ({ ...prev, isPlaying: !prev.isPlaying }));
    }
  };

  const handleReset = () => {
    setSettings(prev => ({ ...prev, isPlaying: false, isVoiceMode: false }));
    const scroller = document.querySelector('.overflow-y-auto');
    if (scroller) scroller.scrollTop = 0;
  };

  const handleAIApply = (generatedText: string) => {
    setText(generatedText);
    handleReset();
  };

  // --- Drag & Drop ---
  const handleDragOver = (e: React.DragEvent) => {
    e.preventDefault();
    setIsDragging(true);
  };

  const handleDragLeave = (e: React.DragEvent) => {
    e.preventDefault();
    setIsDragging(false);
  };

  const handleDrop = async (e: React.DragEvent) => {
    e.preventDefault();
    setIsDragging(false);

    const file = e.dataTransfer.files[0];
    if (file) {
        if (file.type.startsWith('text') || file.name.endsWith('.txt') || file.name.endsWith('.md')) {
            const content = await file.text();
            setText(content);
            handleReset();
        } else {
            alert("Please drop a text file (.txt, .md)");
        }
    }
  };

  return (
    <div 
        className="flex flex-col h-screen bg-black overflow-hidden font-sans relative"
        onDragOver={handleDragOver}
        onDragLeave={handleDragLeave}
        onDrop={handleDrop}
    >
      {/* Drag Overlay */}
      {isDragging && (
          <div className="absolute inset-0 z-50 bg-emerald-900/80 backdrop-blur-sm flex items-center justify-center border-4 border-emerald-500 border-dashed m-4 rounded-xl">
              <div className="text-center text-emerald-100 animate-bounce">
                  <svg xmlns="http://www.w3.org/2000/svg" width="64" height="64" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round" className="mx-auto mb-4"><path d="M14 2H6a2 2 0 0 0-2 2v16a2 2 0 0 0 2 2h12a2 2 0 0 0 2-2V8z"></path><polyline points="14 2 14 8 20 8"></polyline><line x1="12" y1="18" x2="12" y2="12"></line><line x1="9" y1="15" x2="15" y2="15"></line></svg>
                  <h2 className="text-3xl font-bold">Drop text file to load</h2>
              </div>
          </div>
      )}

      {/* Header / Top Bar (Minimalist) */}
      <div className="absolute top-0 left-0 p-4 z-40 opacity-50 hover:opacity-100 transition-opacity">
        <h1 className="text-white font-bold tracking-tighter text-xl pointer-events-none select-none">
          Zen<span className="text-red-500">Prompter</span>
        </h1>
      </div>

      {/* Main Display */}
      <TeleprompterDisplay 
        settings={settings} 
        text={text} 
        onTextChange={handleTextChange} 
        togglePlay={togglePlay}
      />

      {/* Controls */}
      <ControlPanel 
        settings={settings} 
        updateSettings={updateSettings} 
        togglePlay={togglePlay}
        onReset={handleReset}
        openAIModal={() => setAIModalOpen(true)}
        openHelpModal={() => setHelpModalOpen(true)}
        wordCount={text.split(/\s+/).filter(w => w.length > 0).length}
      />

      {/* AI Modal */}
      <AIModal 
        isOpen={isAIModalOpen} 
        onClose={() => setAIModalOpen(false)}
        onApply={handleAIApply}
        currentText={text}
      />

      {/* Help Modal */}
      <HelpModal 
        isOpen={isHelpModalOpen}
        onClose={() => setHelpModalOpen(false)}
      />
    </div>
  );
};

