             >
                {segments.map((seg, i) => {
                    const isPast = seg.isWord && seg.end <= matchedIndex;
                    const isNextWord = seg.isWord && seg.start >= matchedIndex && (
                        i === 0 || segments[i-1].end <= matchedIndex
                    );

                    let className = "transition-colors duration-200 rounded px-1 -mx-1 ";
                    let style = {};

                    if (!seg.isWord) {
                        const prevRead = i > 0 && segments[i-1].end <= matchedIndex;
                        if (prevRead) style = { color: '#4b5563' }; // gray-600
                    } else {
                        if (isPast) {
                            style = { color: '#4b5563' };
                        } else if (isNextWord) {
                            className += "bg-blue-600 text-white shadow-[0_0_15px_rgba(37,99,235,0.5)] scale-105 inline-block origin-center transform"; 
                            // Ensure text color is white for contrast against blue bg
                            style = { color: 'white' };
                        }
                    }

                    return (
                        <span 
                            key={i} 
                            data-active={isNextWord ? "true" : "false"}
                            className={className}
                            style={style}
                        >
                            {seg.text}
                        </span>
                    );
                })}
             </div>
        )}
        <div style={{ height: '50vh' }}></div>
      </div>

      {!isReadOnlyMode && !isFocused && text.trim().length === 0 && (
         <div className="absolute inset-0 flex items-center justify-center pointer-events-none text-gray-500">
             <span className="text-xl">Drop a text file or click to start typing...</span>
         </div>
      )}
    </div>
  );
};

export default TeleprompterDisplay;

import React, { useEffect, useRef, useState, useMemo } from 'react';
import { PrompterSettings } from '../types';

interface TeleprompterDisplayProps {
  settings: PrompterSettings;
  text: string;
  onTextChange: (text: string) => void;
  togglePlay: () => void;
}

interface TextSegment {
  text: string;
  isWord: boolean;
  start: number;
  end: number;
}

// --- Optimization: Levenshtein with cutoff ---
// Calculates distance, but aborts if it exceeds a threshold to save CPU
const levenshteinDistance = (s: string, t: string, maxDist: number = 100): number => {
  if (s === t) return 0;
  if (s.length === 0) return t.length;
  if (t.length === 0) return s.length;

  // Optimization: length difference cut-off
  if (Math.abs(s.length - t.length) > maxDist) return maxDist + 1;

  const d: number[][] = [];
  const n = s.length;
  const m = t.length;

  for (let i = 0; i <= n; i++) d[i] = [i];
  for (let j = 0; j <= m; j++) d[0][j] = j;

  for (let i = 1; i <= n; i++) {
    let minRow = Infinity;
    for (let j = 1; j <= m; j++) {
      const cost = s.charAt(i - 1) === t.charAt(j - 1) ? 0 : 1;
      d[i][j] = Math.min(
        d[i - 1][j] + 1,      // deletion
        d[i][j - 1] + 1,      // insertion
        d[i - 1][j - 1] + cost // substitution
      );
      minRow = Math.min(minRow, d[i][j]);
    }
    // Optimization: If entire row is above maxDist, we can stop early
    if (minRow > maxDist) return maxDist + 1;
  }

  return d[n][m];
};

const TeleprompterDisplay: React.FC<TeleprompterDisplayProps> = ({
  settings,
  text,
  onTextChange,
  togglePlay
}) => {
  const containerRef = useRef<HTMLDivElement>(null);
  const contentEditableRef = useRef<HTMLDivElement>(null);
  const readOnlyContentRef = useRef<HTMLDivElement>(null);

  // Animation Refs
  const lastTimeRef = useRef<number | undefined>(undefined);
  const scrollAccumulator = useRef<number>(0);

  // Voice State
  const recognitionRef = useRef<any>(null);
  const [voiceStatus, setVoiceStatus] = useState<string>('');

  // Using refs for tracking to avoid closure staleness in event loops
  const lastMatchIndexRef = useRef<number>(0);
  const silenceTimerRef = useRef<any>(null);

  const [matchedIndex, setMatchedIndex] = useState<number>(0);
  const [isFocused, setIsFocused] = useState(false);
  const [fatalError, setFatalError] = useState(false);

  // --- Styling Utilities ---
  const getFontFamily = () => {
      switch(settings.fontFamily) {
          case 'serif': return 'font-serif';
          case 'mono': return 'font-mono';
          default: return 'font-sans';
      }
  };

  const getTextColor = () => {
      switch(settings.textColor) {
          case 'yellow': return '#fbbf24'; // amber-400
          case 'green': return '#4ade80'; // green-400
          case 'cyan': return '#22d3ee'; // cyan-400
          default: return 'white';
      }
  };

  // --- Preprocessing ---
  const { segments, normalizedText } = useMemo(() => {
    const segs: TextSegment[] = [];
    let normStr = "";
    let currentNormIndex = 0;
    const wordRegex = /[\p{L}\p{N}]/u;
    let buffer = "";
    let bufferIsWord = false;

    const flush = () => {
      if (buffer.length === 0) return;
      let normLen = 0;
      if (bufferIsWord) {
        for (const char of buffer) {
           if (wordRegex.test(char)) {
             normStr += char.toLowerCase();
             normLen++;
           }
        }
      }
      segs.push({
        text: buffer,
        isWord: bufferIsWord,
        start: currentNormIndex,
        end: currentNormIndex + normLen
      });
      currentNormIndex += normLen;
      buffer = "";
    };

    for (const char of text) {
      const charIsWord = wordRegex.test(char);
      if (buffer.length === 0) {
        bufferIsWord = charIsWord;
      } else if (charIsWord !== bufferIsWord) {
        flush();
        bufferIsWord = charIsWord;
      }
      buffer += char;
    }
    flush();
    return { segments: segs, normalizedText: normStr };
  }, [text]);

  // Reset match index when text changes or mode toggles
  useEffect(() => {
    if (!settings.isVoiceMode) return;
    lastMatchIndexRef.current = 0;
    setMatchedIndex(0);
    setFatalError(false);
  }, [normalizedText, settings.isVoiceMode]);

  // --- Auto-Scroll Animation ---
  useEffect(() => {
    let animationFrameId: number;
    let isRunning = settings.isPlaying;

    const animate = (time: number) => {
      if (!isRunning || !containerRef.current) return;

      if (lastTimeRef.current !== undefined) {
        const deltaTime = Math.min((time - lastTimeRef.current) / 1000, 0.1);
        const pixelsPerSecond = settings.speed * 20; 

        const currentScroll = containerRef.current.scrollTop;
        if (Math.abs(currentScroll - scrollAccumulator.current) > 5) {
             scrollAccumulator.current = currentScroll;
        }

        scrollAccumulator.current += pixelsPerSecond * deltaTime;
        containerRef.current.scrollTop = scrollAccumulator.current;
      }

      lastTimeRef.current = time;
      animationFrameId = requestAnimationFrame(animate);
    };

    if (settings.isPlaying) {
      if (containerRef.current) {
        scrollAccumulator.current = containerRef.current.scrollTop;
      }
      lastTimeRef.current = undefined;
      animationFrameId = requestAnimationFrame(animate);
    }

    return () => {
      isRunning = false;
      cancelAnimationFrame(animationFrameId);
    };
  }, [settings.isPlaying, settings.speed]);

  // --- Voice Following Logic (Deep Logic) ---
  const scrollToActiveSegment = () => {
    if (!readOnlyContentRef.current || !containerRef.current) return;
    const activeSpan = readOnlyContentRef.current.querySelector('[data-active="true"]');
    if (activeSpan) {
        try {
          const rect = activeSpan.getBoundingClientRect();
          const containerRect = containerRef.current.getBoundingClientRect();

          // Calculate desired position (center of viewport)
          const centerOffset = containerRect.height / 2;
          const relativeTop = rect.top - containerRect.top;

          // Smooth scroll target
          const targetScroll = containerRef.current.scrollTop + relativeTop - centerOffset + (rect.height / 2);

          containerRef.current.scrollTo({ top: targetScroll, behavior: 'smooth' });
          scrollAccumulator.current = targetScroll;
        } catch (e) {}
    }
  };

  useEffect(() => {
    // Clean up previous instances strictly
    if (recognitionRef.current) {
        try { recognitionRef.current.stop(); } catch(e) {}
        recognitionRef.current = null;
    }

    if (!settings.isVoiceMode || fatalError) return;

    setVoiceStatus('Initializing...');

    // @ts-ignore
    const SpeechRecognition = window.SpeechRecognition || window.webkitSpeechRecognition;
    if (!SpeechRecognition) {
      setVoiceStatus('Not Supported');
      alert("Speech Recognition API not found. Please use Chrome or Safari.");
      return;
    }

    const recognition = new SpeechRecognition();
    recognition.continuous = true;
    recognition.interimResults = true;
    recognition.lang = navigator.language || 'en-US'; 

    recognition.onstart = () => { 
        setVoiceStatus('Listening...'); 
        // Clear any restart timers
        if (silenceTimerRef.current) clearTimeout(silenceTimerRef.current);
    };

    recognition.onresult = (event: any) => {
         const results = event.results;
         // We only care about the latest result segment
         const latestResult = results[results.length - 1];
         const transcript = latestResult[0].transcript;
         const isFinal = latestResult.isFinal;

         // 1. Normalize Input
         let cleanTranscript = "";
         const regex = /[\p{L}\p{N}]/u;
         for (const char of transcript) {
            if (regex.test(char)) cleanTranscript += char.toLowerCase();
         }

         // Too short to be useful
         if (cleanTranscript.length < 3) return;

         // 2. Define Anchor Window (The "Fingerprint" of what was said)
         // We take the last N characters. 
         // Shorter window = faster reaction but more false positives.
         // Longer window = more accurate but laggy.
         const WINDOW_SIZE = 45; 
         const searchStr = cleanTranscript.slice(-WINDOW_SIZE);

         // 3. Define Search Boundaries (Where to look in the script)
         // We look mostly forward, but a little bit backward (for corrections).
         const currentPos = lastMatchIndexRef.current;
         const LOOK_BACK = 50; 
         const LOOK_AHEAD_LOCAL = 200; // High probability zone
         const LOOK_AHEAD_GLOBAL = 1500; // Low probability zone (paragraph jumps)

         const startLocal = Math.max(0, currentPos - LOOK_BACK);
         const endLocal = Math.min(normalizedText.length, currentPos + LOOK_AHEAD_LOCAL);

         const startGlobal = Math.max(0, currentPos - LOOK_BACK); // We start global search from roughly same spot
         const endGlobal = Math.min(normalizedText.length, currentPos + LOOK_AHEAD_GLOBAL);

         // 4. Scoring Algorithm
         // Find best match. Lower score is better.
         let bestMatchIndex = -1;
         let bestScore = Infinity;

         // Helper to scan a range
         const scanRange = (start: number, end: number, penaltyFactor: number) => {
            const len = searchStr.length;
            // Optimization: Step by 1 char? Or step by chunks? 
            // Step by 1 is safest for accuracy.
            for (let i = start; i <= end - len; i++) {
                const candidate = normalizedText.substr(i, len);

                // Quick check: If first and last char don't match, distance is likely high.
                // This is a heuristic optimization.
                if (candidate[0] !== searchStr[0] && candidate[len-1] !== searchStr[len-1]) {
                    continue; 
                }

                const dist = levenshteinDistance(searchStr, candidate, Math.floor(len * 0.4));

                // Score = Editing Distance + Position Penalty
                // We penalize distance from current cursor to prevent random jumping
                const distancePenalty = Math.abs(i - currentPos) * penaltyFactor;
                const score = dist + distancePenalty;

                // Threshold: Max 35% difference allowed in string content
                if (dist <= len * 0.35) {
                    if (score < bestScore) {
                        bestScore = score;
                        bestMatchIndex = i;
                    }
                }
            }
         };

         // Pass 1: Local Scan (Low penalty for distance)
         // Penalty 0.01 per character distance. 100 chars away = +1 error equivalent.
         scanRange(startLocal, endLocal, 0.01);

         // Pass 2: Global Scan (Higher penalty) - only runs if we didn't find a perfect local match
         // Penalty 0.05 per character. 100 chars away = +5 error equivalent.
         // This means a global match must be MUCH better (more exact) than a local fuzzy match to win.
         if (bestScore > 1) { 
             scanRange(startGlobal, endGlobal, 0.05);
         }

         // 5. Apply Result
         if (bestMatchIndex !== -1) {
             const newIndex = bestMatchIndex + searchStr.length;

             // Check: Don't jump backwards significantly unless the match is PERFECT
             // (Score < 1 means basically exact match close by)
             const isBackward = newIndex < currentPos;
             const isBigJump = Math.abs(newIndex - currentPos) > 100;

             if (isBackward && bestScore > 2) {
                 // Ignore backward jump if it's fuzzy
                 return;
             }

             // Apply
             lastMatchIndexRef.current = newIndex;
             setMatchedIndex(newIndex);
             setVoiceStatus(bestScore < 1.5 ? `Sync: "${searchStr.slice(-10)}"` : 'Adjusting...');
         } else {
             // No match found
             if (isFinal) {
                 // If the sentence ended and we didn't find it, maybe we are totally lost?
                 // For now, do nothing, wait for next sentence.
             }
         }
    };

    recognition.onerror = (event: any) => {
        const errorMsg = event.error ? String(event.error) : 'Unknown Error';
        if (errorMsg === 'no-speech') {
            // Ignore no-speech, it happens constantly in silence
            return;
        }

        console.warn("Speech Recognition Error:", errorMsg);

        if (errorMsg === 'not-allowed' || errorMsg === 'service-not-allowed') {
            setVoiceStatus('Microphone Blocked');
            setFatalError(true);
            recognition.stop();
        } else if (errorMsg === 'network') {
             setVoiceStatus('Network Error');
             // Try to restart after delay
             silenceTimerRef.current = setTimeout(() => {
                 try { recognition.start(); } catch(e) {}
             }, 1000);
        } else if (errorMsg === 'aborted') {
             // Do nothing, likely intentional stop
        } else {
            setVoiceStatus(`Err: ${errorMsg}`);
        }
    };

    recognition.onend = () => {
        // Vital: SpeechRecognition stops automatically after silence or "session end".
        // We must restart it immediately if we are still in Voice Mode.
        if (settings.isVoiceMode && !fatalError) {
           // Small backoff to prevent CPU spin if it crashes instantly
           silenceTimerRef.current = setTimeout(() => {
               if (recognitionRef.current && !fatalError) {
                  try { recognition.start(); } catch(e) {
                      console.log("Restart failed", e);
                  }
               }
           }, 100);
        } else { 
            setVoiceStatus(''); 
        }
    };

    recognitionRef.current = recognition;
    try { recognition.start(); } catch (e) { console.error("Failed to start recognition", e); }

    return () => {
       if (silenceTimerRef.current) clearTimeout(silenceTimerRef.current);
       if (recognitionRef.current) {
        // Remove onend to prevent auto-restart during unmount
        recognitionRef.current.onend = null;
        recognitionRef.current.stop();
      }
    };
  }, [settings.isVoiceMode, fatalError, normalizedText]);

  useEffect(() => {
     if (settings.isVoiceMode) scrollToActiveSegment();
  }, [matchedIndex, settings.isVoiceMode]);

  useEffect(() => {
    const handleKeyDown = (e: KeyboardEvent) => {
      if (e.code === 'Space') {
        if (settings.isPlaying || settings.isVoiceMode || document.activeElement !== contentEditableRef.current) {
          e.preventDefault();
          togglePlay();
        }
      }
    };
    window.addEventListener('keydown', handleKeyDown);
    return () => window.removeEventListener('keydown', handleKeyDown);
  }, [settings.isPlaying, settings.isVoiceMode, togglePlay]);

  const isReadOnlyMode = settings.isPlaying || settings.isVoiceMode;

  return (
    <div className="relative flex-1 overflow-hidden bg-black w-full h-full">
      {settings.isVoiceMode && (
          <div className="absolute top-20 right-4 z-30 flex items-center gap-2 pointer-events-none">
               <div className={`px-4 py-2 rounded-full text-xs font-mono shadow-lg flex items-center gap-2 transition-all ${fatalError ? 'bg-red-900/90 border border-red-500 text-red-100' : 'bg-purple-900/90 border border-purple-500 text-purple-100'}`}>
                  {!fatalError && <div className="w-2 h-2 bg-red-500 rounded-full animate-ping"></div>}
                  {voiceStatus}
               </div>
          </div>
      )}

      <div className="absolute top-1/2 left-0 right-0 z-20 flex items-center justify-center pointer-events-none opacity-40">
        <div className="w-full h-0 border-t-2 border-red-500 shadow-[0_0_10px_rgba(239,68,68,0.8)]"></div>
        <div className="absolute right-4 -top-3 text-red-500 text-xs font-mono uppercase tracking-widest bg-black px-1">Eye Level</div>
      </div>

      <div 
        ref={containerRef}
        className={`w-full h-full overflow-y-auto no-scrollbar relative z-10 scroll-smooth ${isReadOnlyMode ? 'cursor-none' : 'cursor-text'}`}
        onClick={() => { if(settings.isPlaying) togglePlay(); }}
      >
        <div style={{ height: '50vh' }}></div>

        <div 
          ref={contentEditableRef}
          contentEditable={!isReadOnlyMode}
          onInput={(e) => onTextChange(e.currentTarget.innerText)}
          onFocus={() => setIsFocused(true)}
          onBlur={() => setIsFocused(false)}
          suppressContentEditableWarning={true}
          className={`
            max-w-4xl mx-auto px-8 outline-none
            transition-all duration-300 ease-in-out
            ${settings.isMirrored ? 'scale-x-[-1]' : ''}
            ${isReadOnlyMode ? 'hidden' : 'block'}
            ${getFontFamily()}
          `}
          style={{ 
            fontSize: `${settings.fontSize}px`,
            lineHeight: '1.5',
            color: getTextColor(),
            textAlign: settings.isMirrored ? 'right' : 'left',
            whiteSpace: 'pre-wrap' 
          }}
        >
            {text}
        </div>

        {isReadOnlyMode && (
             <div 
                ref={readOnlyContentRef}
                className={`
                    max-w-4xl mx-auto px-8 outline-none
                    transition-all duration-300 ease-in-out
                    ${settings.isMirrored ? 'scale-x-[-1]' : ''}
                    ${getFontFamily()}
                `}
                style={{ 
                    fontSize: `${settings.fontSize}px`,
                    lineHeight: '1.5',
                    textAlign: settings.isMirrored ? 'right' : 'left',
                    whiteSpace: 'pre-wrap',
                    color: getTextColor()
                }}
             >
                {segments.map((seg, i) => {
                    // Logic for display:
                    // If matchedIndex is past the end of this segment, it's read.
                    const isPast = seg.isWord && seg.end <= matchedIndex;

                    // Logic for Active Word:
                    // It is the FIRST word where seg.start >= matchedIndex
                    // We need to check if the previous word was read.
                    const isNextWord = seg.isWord && seg.start >= matchedIndex && (
                        i === 0 || segments[i-1].end <= matchedIndex || !segments[i-1].isWord
                    );

                    // Small correction: ensure only one word is highlighted as active
                    // The map runs sequentially, so we can rely on React render, but "isNextWord" logic above 
                    // might be true for multiple consecutive words if they are close. 
                    // Actually, `seg.start >= matchedIndex` makes all future words candidates.
                    // We need strictly the *first* one. 
                    // Refined logic: A word is active if it contains the matchedIndex OR it is the immediate next one.

                    // Simpler logic for Highlighting:
                    // Active = The word that contains the current cursor, or immediately follows it.
                    const isActive = seg.isWord && matchedIndex >= seg.start && matchedIndex < seg.end;

                    // Fallback: If cursor is between words (space), highlight the NEXT word.
                    const isNextPending = seg.isWord && seg.start >= matchedIndex && (i===0 || segments[i-1].end <= matchedIndex);

                    // We prefer showing the word currently being spoken (isActive) or the very next one.
                    // To avoid multiple highlights, we could check if we already highlighted one in this render cycle? 
                    // Can't do that easily in map.
                    // Instead, let's rely on strict Index comparison.

                    // If we are "inside" a word, highlight it.
                    // If we are "between" words, highlight the next one.
                    let showActive = false;
                    if (seg.isWord) {
                        if (matchedIndex >= seg.start && matchedIndex < seg.end) {
                            showActive = true;
                        } else if (matchedIndex < seg.start) {
                            // Check if this is the very first word AFTER matchedIndex
                            // We can approximate this by checking if the previous segment ended before matchedIndex
                            // (Scanning array in render is fine for small N, but here N is big).

                            // Let's use the `data-active` attribute in `scrollToActiveSegment` to find it,
                            // relying on CSS logic: first-of-type? No.

                            // Let's stick to the previous reliable logic but tighten it.
                            // Is this the first unread word?
                            const prevWordEnd = i > 0 ? segments[i-1].end : 0;
                            // If cursor is past previous word, and before this word starts (or inside this word)
                            if (matchedIndex >= prevWordEnd && matchedIndex < seg.end) {
                                showActive = true;
                            }
                        }
                    }

                    let className = "transition-colors duration-200 rounded px-1 -mx-1 ";
                    let style = {};

                    if (!seg.isWord) {
                         // Punctuation logic: dark if past
                         if (seg.end <= matchedIndex) style = { color: '#4b5563' };
                    } else {
                        if (isPast && !showActive) {
                            style = { color: '#4b5563' };
                        } else if (showActive) {
                            className += "bg-blue-600 text-white shadow-[0_0_15px_rgba(37,99,235,0.5)] scale-105 inline-block origin-center transform z-10 relative"; 
                            style = { color: 'white' };
                        }
                    }

                    return (
                        <span 
                            key={i} 
                            data-active={showActive ? "true" : "false"}
                            className={className}
                            style={style}
                        >
                            {seg.text}
                        </span>
                    );
                })}
             </div>
        )}
        <div style={{ height: '50vh' }}></div>
      </div>

      {!isReadOnlyMode && !isFocused && text.trim().length === 0 && (
         <div className="absolute inset-0 flex items-center justify-center pointer-events-none text-gray-500">
             <span className="text-xl">Drop a text file or click to start typing...</span>
         </div>
      )}
    </div>
  );
};

