             const candidate = normalizedText.substr(i, searchStr.length);
             const dist = levenshteinDistance(searchStr, candidate, Math.floor(searchStr.length * 0.4));

             let penalty = 0;
             const positionDrift = i - currentPos;

             if (positionDrift < 0) {
                 penalty += Math.abs(positionDrift) * 0.2;
             } else {
                 penalty += positionDrift * 0.01; // Be more forgiving of forward jumps
             }

             const score = dist + penalty;

             if (dist <= searchStr.length * 0.35 && score < bestScore) {
                 bestScore = score;
                 bestMatchIndex = i;
             }
         }

         if (bestMatchIndex !== -1) {
             const newIndex = bestMatchIndex + searchStr.length - 1;

             if (Math.abs(newIndex - currentPos) > 1) { // Only update on significant moves
                 stuckCounterRef.current = 0; // Reset stuck counter on a successful move
                 lastMatchIndexRef.current = newIndex;
                 setMatchedIndex(newIndex);
                 setVoiceStatus('追踪中...');
                 if (isReacquiringLockRef.current) {
                     isReacquiringLockRef.current = false;
                 }
             } else {
                 stuckCounterRef.current++;
             }
         } else {
             stuckCounterRef.current++;
         }

         // FAULT TOLERANCE: Unstuck mechanism
         if (stuckCounterRef.current >= 3) { // If 3 results come in with no significant move
             if (!isReacquiringLockRef.current) {
                 isReacquiringLockRef.current = true;
                 setVoiceStatus('重新同步...'); // Give user feedback
             }
             stuckCounterRef.current = 0; // Reset after triggering
         }
    };

    recognition.onerror = (event: any) => {
        const errorMsg = event.error ? String(event.error) : 'Unknown Error';
        if (errorMsg === 'no-speech') return;
        if (errorMsg === 'not-allowed') {
            setVoiceStatus('麦克风被禁用');
            setFatalError(true);
            recognition.stop();
        } else if (errorMsg === 'network') {
             setVoiceStatus('网络错误');
             setTimeout(() => { try { recognition.start(); } catch(e) {} }, 1000);
        } else if (errorMsg !== 'aborted') {
            setVoiceStatus(`错误: ${errorMsg}`);
        }
    };

    recognition.onend = () => {
        if (settings.isVoiceMode && !fatalError) {
           setTimeout(() => {
               if (recognitionRef.current && !fatalError) {
                  try { recognition.start(); } catch(e) {}
               }
           }, 250);
        } else { 
            setVoiceStatus(''); 
        }
    };

    recognitionRef.current = recognition;
    try { recognition.start(); } catch (e) { console.error("Failed to start recognition", e); }

    return () => {
       if (silenceTimerRef.current) clearTimeout(silenceTimerRef.current);
       if (recognitionRef.current) {
        recognitionRef.current.onend = null;
        recognitionRef.current.stop();
      }
    };
  }, [settings.isVoiceMode, fatalError, normalizedText]);

