        {isReadOnlyMode && (
             <div 
                ref={readOnlyContentRef}
                className={`
                    max-w-4xl mx-auto px-8 outline-none
                    ${settings.isMirrored ? 'scale-x-[-1]' : ''}
                    ${getFontFamily()}
                `}
                style={{ 
                    fontSize: `${settings.fontSize}px`,
                    lineHeight: 1.5,
                    textAlign: settings.isMirrored ? 'right' : 'left',
                    whiteSpace: 'pre-wrap',
                    color: getTextColor()
                }}
             >
                {segments.map((seg, i) => {
                    const isPast = seg.isWordChar && seg.normIndex < matchedIndex;
                    const isActive = seg.normIndex === matchedIndex;

                    let className = "transition-all duration-150 ease-in-out";
                    let style = {};

                    if (isPast) {
                        style = { color: '#4b5563' };
                    } else if (isActive) {
                        className += " bg-blue-600 text-white rounded shadow-lg scale-110 inline-block";
                    }

                    return (
                        <span 
                            key={i} 
                            data-active={isActive ? "true" : "false"}
                            className={className}
                            style={style}
                        >
